package automation

import (
	"github.com/gin-gonic/gin"

	"github.com/smartcontractkit/chainlink-testing-framework/framework/components/fake"
)

func RegisterRoutes() error {
	// Mocks that serve signed reports from DataStreams API.
	// Exact values and feeds they contain remains unknown. These values were either copied from actual API responses or other tests.
	err := fake.Func("GET", "/api/v1/reports/bulk", func(ctx *gin.Context) {
		ctx.JSON(200, gin.H{
			"reports": []map[string]any{
				{
					"feedID":                "0x00028c915d6af0fd66bba2d0fc9405226bca8d6806333121a7d9832103d1563c",
					"validFromTimestamp":    0,
					"observationsTimestamp": 0,
					"fullReport":            "",
				},
			},
		})
	})
	if err != nil {
		return err
	}

	return fake.Func("GET", "/client", func(ctx *gin.Context) {
		ctx.JSON(200, gin.H{
			"chainlinkBlob": "",
		})
	})
}
